using UnityEngine;
using UnityEngine.UI;
using System;
using System.Collections.Generic;

// PlayerStats.cs - Stores all player statistics
public class PlayerStats : MonoBehaviour
{
    public static PlayerStats Instance;

    public float maxHealth = 100f;
    public float currentHealth = 100f;
    public int currency = 500;
    public int premiumCurrency = 0;
    public int playerLevel = 1;
    public float baseAttackDamage = 10f;
    public float attackMultiplier = 1.0f;
    public float defenseMultiplier = 1.0f;
    public float criticalChance = 0.05f;
    public float criticalMultiplier = 2.0f;
    public int armor = 0;

    public List<string> ownedItems = new List<string>();
    public string equippedWeapon = "basic_sword";
    public string equippedArmor = "basic_armor";

    public event Action<float, float> OnHealthChanged;
    public event Action<int> OnCurrencyChanged;
    public event Action<int> OnPremiumCurrencyChanged;
    public event Action OnPlayerDied;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        LoadStats();
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        OnCurrencyChanged?.Invoke(currency);
        SaveStats();
    }

    public void AddPremiumCurrency(int amount)
    {
        premiumCurrency += amount;
        OnPremiumCurrencyChanged?.Invoke(premiumCurrency);
        SaveStats();
    }

    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            OnCurrencyChanged?.Invoke(currency);
            SaveStats();
            return true;
        }
        return false;
    }

    public bool SpendPremiumCurrency(int amount)
    {
        if (premiumCurrency >= amount)
        {
            premiumCurrency -= amount;
            OnPremiumCurrencyChanged?.Invoke(premiumCurrency);
            SaveStats();
            return true;
        }
        return false;
    }

    public void Heal(float amount)
    {
        currentHealth = Mathf.Min(currentHealth + amount, maxHealth);
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
        SaveStats();
    }

    public void FullHeal()
    {
        currentHealth = maxHealth;
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
        SaveStats();
    }

    public void IncreaseMaxHealth(float amount)
    {
        maxHealth += amount;
        currentHealth += amount;
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
        SaveStats();
    }

    public void AddItem(string itemId)
    {
        if (!ownedItems.Contains(itemId))
        {
            ownedItems.Add(itemId);
            SaveStats();
        }
    }

    public bool HasItem(string itemId)
    {
        return ownedItems.Contains(itemId);
    }

    public void EquipWeapon(string itemId)
    {
        if (ownedItems.Contains(itemId))
        {
            equippedWeapon = itemId;
            SaveStats();
        }
    }

    public void EquipArmor(string itemId)
    {
        if (ownedItems.Contains(itemId))
        {
            equippedArmor = itemId;
            SaveStats();
        }
    }

    public void LevelUp()
    {
        playerLevel++;
        maxHealth += 10f;
        currentHealth = maxHealth;
        baseAttackDamage += 2f;
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
        SaveStats();
    }

    public void SaveStats()
    {
        PlayerPrefs.SetFloat("MaxHealth", maxHealth);
        PlayerPrefs.SetFloat("CurrentHealth", currentHealth);
        PlayerPrefs.SetInt("Currency", currency);
        PlayerPrefs.SetInt("PremiumCurrency", premiumCurrency);
        PlayerPrefs.SetInt("PlayerLevel", playerLevel);
        PlayerPrefs.SetFloat("BaseAttackDamage", baseAttackDamage);
        PlayerPrefs.SetFloat("AttackMultiplier", attackMultiplier);
        PlayerPrefs.SetFloat("DefenseMultiplier", defenseMultiplier);
        PlayerPrefs.SetFloat("CriticalChance", criticalChance);
        PlayerPrefs.SetFloat("CriticalMultiplier", criticalMultiplier);
        PlayerPrefs.SetInt("Armor", armor);
        PlayerPrefs.SetString("EquippedWeapon", equippedWeapon);
        PlayerPrefs.SetString("EquippedArmor", equippedArmor);
        PlayerPrefs.SetString("OwnedItems", string.Join(",", ownedItems));
        PlayerPrefs.Save();
    }

    public void LoadStats()
    {
        maxHealth = PlayerPrefs.GetFloat("MaxHealth", 100f);
        currentHealth = PlayerPrefs.GetFloat("CurrentHealth", 100f);
        currency = PlayerPrefs.GetInt("Currency", 500);
        premiumCurrency = PlayerPrefs.GetInt("PremiumCurrency", 0);
        playerLevel = PlayerPrefs.GetInt("PlayerLevel", 1);
        baseAttackDamage = PlayerPrefs.GetFloat("BaseAttackDamage", 10f);
        attackMultiplier = PlayerPrefs.GetFloat("AttackMultiplier", 1.0f);
        defenseMultiplier = PlayerPrefs.GetFloat("DefenseMultiplier", 1.0f);
        criticalChance = PlayerPrefs.GetFloat("CriticalChance", 0.05f);
        criticalMultiplier = PlayerPrefs.GetFloat("CriticalMultiplier", 2.0f);
        armor = PlayerPrefs.GetInt("Armor", 0);
        equippedWeapon = PlayerPrefs.GetString("EquippedWeapon", "basic_sword");
        equippedArmor = PlayerPrefs.GetString("EquippedArmor", "basic_armor");

        string itemsString = PlayerPrefs.GetString("OwnedItems", "");
        ownedItems = new List<string>();
        if (!string.IsNullOrEmpty(itemsString))
        {
            ownedItems.AddRange(itemsString.Split(','));
        }
    }

    public void ResetStats()
    {
        PlayerPrefs.DeleteAll();
        maxHealth = 100f;
        currentHealth = 100f;
        currency = 500;
        premiumCurrency = 0;
        playerLevel = 1;
        baseAttackDamage = 10f;
        attackMultiplier = 1.0f;
        defenseMultiplier = 1.0f;
        criticalChance = 0.05f;
        criticalMultiplier = 2.0f;
        armor = 0;
        ownedItems.Clear();
        equippedWeapon = "basic_sword";
        equippedArmor = "basic_armor";
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
        OnCurrencyChanged?.Invoke(currency);
    }
}

// DamageCalculator.cs - Client-side damage calculation
public class DamageCalculator : MonoBehaviour
{
    public static DamageCalculator Instance;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    public DamageResult CalculatePlayerDamage(EnemyData target)
    {
        PlayerStats stats = PlayerStats.Instance;
        DamageResult result = new DamageResult();

        float weaponDamage = GetWeaponDamage(stats.equippedWeapon);
        float rawDamage = (stats.baseAttackDamage + weaponDamage) * stats.attackMultiplier;

        bool isCritical = UnityEngine.Random.value <= stats.criticalChance;
        if (isCritical)
        {
            rawDamage *= stats.criticalMultiplier;
            result.isCritical = true;
        }

        float damageReduction = target.armor / (target.armor + 100f);
        float finalDamage = rawDamage * (1f - damageReduction);

        float elementalBonus = GetElementalBonus(stats.equippedWeapon, target.elementType);
        finalDamage *= elementalBonus;

        finalDamage = Mathf.Max(finalDamage, 1f);

        result.damage = Mathf.RoundToInt(finalDamage);
        result.rawDamage = rawDamage;
        result.damageReduction = damageReduction;
        result.elementalMultiplier = elementalBonus;

        return result;
    }

    public DamageResult CalculateEnemyDamage(float enemyAttack, float enemyMultiplier = 1.0f)
    {
        PlayerStats stats = PlayerStats.Instance;
        DamageResult result = new DamageResult();

        float rawDamage = enemyAttack * enemyMultiplier;

        float armorValue = stats.armor + GetArmorValue(stats.equippedArmor);
        float damageReduction = armorValue / (armorValue + 100f);
        float finalDamage = rawDamage * (1f - damageReduction) / stats.defenseMultiplier;

        finalDamage = Mathf.Max(finalDamage, 1f);

        result.damage = Mathf.RoundToInt(finalDamage);
        result.rawDamage = rawDamage;
        result.damageReduction = damageReduction;

        return result;
    }

    public void ApplyDamageToPlayer(float enemyAttack, float enemyMultiplier = 1.0f)
    {
        DamageResult result = CalculateEnemyDamage(enemyAttack, enemyMultiplier);
        PlayerStats stats = PlayerStats.Instance;

        stats.currentHealth -= result.damage;
        stats.currentHealth = Mathf.Max(stats.currentHealth, 0f);

        stats.OnHealthChanged?.Invoke(stats.currentHealth, stats.maxHealth);

        if (stats.currentHealth <= 0)
        {
            stats.OnPlayerDied?.Invoke();
        }

        stats.SaveStats();
    }

    public void ApplyDamageToEnemy(EnemyData enemy)
    {
        DamageResult result = CalculatePlayerDamage(enemy);
        enemy.currentHealth -= result.damage;
        enemy.currentHealth = Mathf.Max(enemy.currentHealth, 0f);

        if (enemy.currentHealth <= 0)
        {
            OnEnemyDefeated(enemy);
        }
    }

    private void OnEnemyDefeated(EnemyData enemy)
    {
        PlayerStats.Instance.AddCurrency(enemy.currencyReward);

        if (UnityEngine.Random.value <= enemy.premiumCurrencyDropChance)
        {
            PlayerStats.Instance.AddPremiumCurrency(enemy.premiumCurrencyReward);
        }
    }

    private float GetWeaponDamage(string weaponId)
    {
        ShopItem item = ShopDatabase.Instance?.GetItem(weaponId);
        if (item != null)
        {
            return item.statBonus;
        }

        switch (weaponId)
        {
            case "basic_sword": return 5f;
            case "iron_sword": return 15f;
            case "steel_sword": return 30f;
            case "fire_sword": return 45f;
            case "legendary_blade": return 80f;
            default: return 5f;
        }
    }

    private float GetArmorValue(string armorId)
    {
        ShopItem item = ShopDatabase.Instance?.GetItem(armorId);
        if (item != null)
        {
            return item.statBonus;
        }

        switch (armorId)
        {
            case "basic_armor": return 5f;
            case "iron_armor": return 20f;
            case "steel_armor": return 40f;
            case "enchanted_armor": return 65f;
            case "legendary_armor": return 100f;
            default: return 5f;
        }
    }

    private float GetElementalBonus(string weaponId, ElementType enemyElement)
    {
        ElementType weaponElement = GetWeaponElement(weaponId);

        if (weaponElement == ElementType.Fire && enemyElement == ElementType.Nature) return 1.5f;
        if (weaponElement == ElementType.Water && enemyElement == ElementType.Fire) return 1.5f;
        if (weaponElement == ElementType.Nature && enemyElement == ElementType.Water) return 1.5f;
        if (weaponElement == ElementType.Light && enemyElement == ElementType.Dark) return 1.75f;
        if (weaponElement == ElementType.Dark && enemyElement == ElementType.Light) return 1.75f;

        if (weaponElement == ElementType.Fire && enemyElement == ElementType.Water) return 0.5f;
        if (weaponElement == ElementType.Water && enemyElement == ElementType.Nature) return 0.5f;
        if (weaponElement == ElementType.Nature && enemyElement == ElementType.Fire) return 0.5f;

        return 1.0f;
    }

    private ElementType GetWeaponElement(string weaponId)
    {
        ShopItem item = ShopDatabase.Instance?.GetItem(weaponId);
        if (item != null)
        {
            return item.elementType;
        }
        return ElementType.None;
    }
}

