// PriceCalculator.cs - Client-side price calculations
public class PriceCalculator : MonoBehaviour
{
    public static PriceCalculator Instance;

    public float saleMultiplier = 1.0f;
    public bool isSaleActive = false;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    public int CalculatePrice(ShopItem item)
    {
        if (item.isPremiumOnly)
        {
            return CalculatePremiumPrice(item);
        }

        int basePrice = item.baseCurrencyPrice;
        float priceModifier = 1.0f;

        if (isSaleActive)
        {
            priceModifier *= saleMultiplier;
        }

        int finalPrice = Mathf.RoundToInt(basePrice * priceModifier);
        return Mathf.Max(finalPrice, 1);
    }

    public int CalculatePremiumPrice(ShopItem item)
    {
        int basePrice = item.premiumCurrencyPrice;
        float priceModifier = 1.0f;

        if (isSaleActive)
        {
            priceModifier *= saleMultiplier;
        }

        int finalPrice = Mathf.RoundToInt(basePrice * priceModifier);
        return Mathf.Max(finalPrice, 1);
    }

    public int CalculateSellPrice(ShopItem item)
    {
        return Mathf.RoundToInt(item.baseCurrencyPrice * 0.3f);
    }

    public void ActivateSale(float discount)
    {
        isSaleActive = true;
        saleMultiplier = 1f - discount;
    }

    public void DeactivateSale()
    {
        isSaleActive = false;
        saleMultiplier = 1.0f;
    }
}

// ShopManager.cs - Handles purchases and item management
public class ShopManager : MonoBehaviour
{
    public static ShopManager Instance;

    public event Action<ShopItem> OnItemPurchased;
    public event Action<string> OnPurchaseFailed;

    private Dictionary<string, int> purchaseCounts = new Dictionary<string, int>();

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    public PurchaseResult TryPurchaseItem(string itemId)
    {
        ShopItem item = ShopDatabase.Instance.GetItem(itemId);
        if (item == null)
        {
            OnPurchaseFailed?.Invoke("Item not found.");
            return PurchaseResult.ItemNotFound;
        }

        PlayerStats stats = PlayerStats.Instance;

        // Check level requirement
        if (stats.playerLevel < item.requiredLevel)
        {
            OnPurchaseFailed?.Invoke($"Requires level {item.requiredLevel}.");
            return PurchaseResult.LevelTooLow;
        }

        // Check purchase count limit
        if (item.maxPurchaseCount > 0)
        {
            int count = GetPurchaseCount(itemId);
            if (count >= item.maxPurchaseCount)
            {
                OnPurchaseFailed?.Invoke("Maximum purchases reached.");
                return PurchaseResult.MaxPurchasesReached;
            }
        }

        // Check if already owned (for non-consumable equipment)
        if (IsEquipmentType(item.itemType) && stats.HasItem(itemId))
        {
            OnPurchaseFailed?.Invoke("Already owned.");
            return PurchaseResult.AlreadyOwned;
        }

        // Process payment
        bool paymentSuccess;
        if (item.isPremiumOnly)
        {
            int price = PriceCalculator.Instance.CalculatePremiumPrice(item);
            paymentSuccess = stats.SpendPremiumCurrency(price);
            if (!paymentSuccess)
            {
                OnPurchaseFailed?.Invoke("Not enough premium currency.");
                return PurchaseResult.InsufficientPremiumCurrency;
            }
        }
        else
        {
            int price = PriceCalculator.Instance.CalculatePrice(item);
            paymentSuccess = stats.SpendCurrency(price);
            if (!paymentSuccess)
            {
                OnPurchaseFailed?.Invoke("Not enough currency.");
                return PurchaseResult.InsufficientCurrency;
            }
        }

        // Apply item effects
        ApplyItemEffects(item);

        // Track purchase
        IncrementPurchaseCount(itemId);

        OnItemPurchased?.Invoke(item);
        return PurchaseResult.Success;
    }

    public PurchaseResult TrySellItem(string itemId)
    {
        PlayerStats stats = PlayerStats.Instance;
        ShopItem item = ShopDatabase.Instance.GetItem(itemId);

        if (item == null)
        {
            return PurchaseResult.ItemNotFound;
        }

        if (!stats.HasItem(itemId))
        {
            OnPurchaseFailed?.Invoke("You don't own this item.");
            return PurchaseResult.ItemNotFound;
        }

        if (stats.equippedWeapon == itemId || stats.equippedArmor == itemId)
        {
            OnPurchaseFailed?.Invoke("Unequip item before selling.");
            return PurchaseResult.ItemEquipped;
        }

        int sellPrice = PriceCalculator.Instance.CalculateSellPrice(item);
        stats.ownedItems.Remove(itemId);
        stats.AddCurrency(sellPrice);
        stats.SaveStats();

        return PurchaseResult.Success;
    }

    private void ApplyItemEffects(ShopItem item)
    {
        PlayerStats stats = PlayerStats.Instance;

        switch (item.itemType)
        {
            case ItemType.Weapon:
                stats.AddItem(item.itemId);
                stats.EquipWeapon(item.itemId);
                break;

            case ItemType.Armor:
                stats.AddItem(item.itemId);
                stats.EquipArmor(item.itemId);
                break;

            case ItemType.HealthPotion:
                stats.Heal(item.statBonus);
                break;

            case ItemType.AttackBoost:
                stats.attackMultiplier += item.statBonus;
                stats.SaveStats();
                break;

            case ItemType.DefenseBoost:
                stats.defenseMultiplier += item.statBonus;
                stats.SaveStats();
                break;

            case ItemType.CritBoost:
                stats.criticalChance += item.statBonus;
                stats.criticalChance = Mathf.Min(stats.criticalChance, 1f);
                stats.SaveStats();
                break;

            case ItemType.CurrencyBooster:
                stats.AddItem(item.itemId);
                stats.SaveStats();
                break;

            case ItemType.Consumable:
                // Generic consumable handling
                break;

            case ItemType.Cosmetic:
                stats.AddItem(item.itemId);
                stats.SaveStats();
                break;
        }
    }

    private bool IsEquipmentType(ItemType type)
    {
        return type == ItemType.Weapon || type == ItemType.Armor || type == ItemType.Cosmetic;
    }

    private int GetPurchaseCount(string itemId)
    {
        if (purchaseCounts.ContainsKey(itemId))
        {
            return purchaseCounts[itemId];
        }
        return PlayerPrefs.GetInt("PurchaseCount_" + itemId, 0);
    }

    private void IncrementPurchaseCount(string itemId)
    {
        int count = GetPurchaseCount(itemId) + 1;
        purchaseCounts[itemId] = count;
        PlayerPrefs.SetInt("PurchaseCount_" + itemId, count);
        PlayerPrefs.Save();
    }

    public bool CanAfford(ShopItem item)
    {
        PlayerStats stats = PlayerStats.Instance;
        if (item.isPremiumOnly)
        {
            return stats.premiumCurrency >= PriceCalculator.Instance.CalculatePremiumPrice(item);
        }
        return stats.currency >= PriceCalculator.Instance.CalculatePrice(item);
    }

    public bool MeetsRequirements(ShopItem item)
    {
        PlayerStats stats = PlayerStats.Instance;
        return stats.playerLevel >= item.requiredLevel;
    }
}

public enum PurchaseResult
{
    Success,
    InsufficientCurrency,
    InsufficientPremiumCurrency,
    ItemNotFound,
    AlreadyOwned,
    LevelTooLow,
    MaxPurchasesReached,
    ItemEquipped
}

// IAPManager.cs - In-App Purchase handler
public class IAPManager : MonoBehaviour
{
    public static IAPManager Instance;

    public event Action<string> OnPurchaseComplete;
    public event Action<string> OnPurchaseFail;

    // IAP Product IDs
    public const string PRODUCT_100_GEMS = "com.game.gems100";
    public const string PRODUCT_500_GEMS = "com.game.gems500";
    public const string PRODUCT_1000_GEMS = "com.game.gems1000";
    public const string PRODUCT_STARTER_PACK = "com.game.starterpack";
    public const string PRODUCT_REMOVE_ADS = "com.game.removeads";

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        InitializePurchasing();
    }

    private void InitializePurchasing()
    {
        // In a real implementation, initialize Unity IAP here
        // using UnityEngine.Purchasing;
        Debug.Log("IAP Manager initialized. Connect Unity IAP for real purchases.");
    }

    public void PurchaseProduct(string productId)
    {
        // In production, this would call Unity IAP's BuyProductID
        Debug.Log($"Attempting to purchase: {productId}");

        // Simulated purchase for development
        ProcessPurchase(productId);
    }

    private void ProcessPurchase(string productId)
    {
        PlayerStats stats = PlayerStats.Instance;

        switch (productId)
        {
            case PRODUCT_100_GEMS:
                stats.AddPremiumCurrency(100);
                break;

            case PRODUCT_500_GEMS:
                stats.AddPremiumCurrency(500);
                break;

            case PRODUCT_1000_GEMS:
                stats.AddPremiumCurrency(1000);
                break;

            case PRODUCT_STARTER_PACK:
                stats.AddPremiumCurrency(200);
                stats.AddCurrency(5000);
                stats.IncreaseMaxHealth(50f);
                stats.attackMultiplier += 0.2f;
                stats.SaveStats();
                break;

            case PRODUCT_REMOVE_ADS:
                PlayerPrefs.SetInt("AdsRemoved", 1);
                PlayerPrefs.Save();
                break;

            default:
                OnPurchaseFail?.Invoke("Unknown product.");
                return;
        }

        OnPurchaseComplete?.Invoke(productId);
    }

    public bool AreAdsRemoved()
    {
        return PlayerPrefs.GetInt("AdsRemoved", 0) == 1;
    }

    public void RestorePurchases()
    {
        // In production, restore purchases via platform-specific APIs
        Debug.Log("Restoring purchases...");
    }
}

// CombatManager.cs - Manages combat encounters
public class CombatManager : MonoBehaviour
{
    public static CombatManager Instance;

    public EnemyData currentEnemy;
    public bool isInCombat = false;

    public event Action<EnemyData> OnCombatStarted;
    public event Action<DamageResult> OnPlayerAttacked;
    public event Action<DamageResult> OnEnemyAttacked;
    public event Action<EnemyData> OnEnemyDefeated;
    public event Action OnPlayerDefeated;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
        }
        else
        {
            Destroy(gameObject);
        }
    }

    public void StartCombat(EnemyData enemy)
    {
        currentEnemy = enemy;
        currentEnemy.currentHealth = currentEnemy.maxHealth;
        isInCombat = true;
        OnCombatStarted?.Invoke(currentEnemy);
    }

    public void PlayerAttack()
    {
        if (!isInCombat || currentEnemy == null) return;

        DamageResult result = DamageCalculator.Instance.CalculatePlayerDamage(currentEnemy);
        currentEnemy.currentHealth -= result.damage;
        currentEnemy.currentHealth = Mathf.Max(currentEnemy.currentHealth, 0f);

        OnPlayerAttacked?.Invoke(result);

        if (currentEnemy.currentHealth <= 0)
        {
            HandleEnemyDefeated();
        }
    }

    public void EnemyAttack()
    {
        if (!isInCombat || currentEnemy == null) return;

        DamageResult result = DamageCalculator.Instance.CalculateEnemyDamage(
            currentEnemy.attackDamage, currentEnemy.attackMultiplier);

        PlayerStats stats = PlayerStats.Instance;
        stats.currentHealth -= result.damage;
        stats.currentHealth = Mathf.Max(stats.currentHealth, 0f);

        OnEnemyAttacked?.Invoke(result);

        if (stats.currentHealth <= 0)
        {
            HandlePlayerDefeated();
        }

        stats.SaveStats();
    }

    private void HandleEnemyDefeated()
    {
        isInCombat = false;
        PlayerStats stats = PlayerStats.Instance;

        int currencyReward = currentEnemy.currencyReward;
        if (stats.HasItem("currency_doubler"))
        {
            currencyReward *= 2;
        }

        stats.AddCurrency(currencyReward);

        if (UnityEngine.Random.value <= currentEnemy.premiumCurrencyDropChance)
        {
            stats.AddPremiumCurrency(currentEnemy.premiumCurrencyReward);
        }

        OnEnemyDefeated?.Invoke(currentEnemy);
        currentEnemy = null;
    }

    private void HandlePlayerDefeated()
    {
        isInCombat = false;
        OnPlayerDefeated?.Invoke();
        currentEnemy = null;
    }

    public void FleeFromCombat()
    {
        if (!isInCombat) return;

        isInCombat = false;
        currentEnemy = null;
    }

    public void UseHealthPotion()
    {
        if (!isInCombat) return;

        ShopItem smallPotion = ShopDatabase.Instance.GetItem("health_potion_small");
        ShopItem largePotion = ShopDatabase.Instance.GetItem("health_potion_large");

        // Try to use the best available potion
        // In a real game, you'd have an inventory system tracking consumable quantities
        PlayerStats.Instance.Heal(25f);
    }
}

// GameUIManager.cs - Simple UI management
public class GameUIManager : MonoBehaviour
{
    [Header("HUD Elements")]
    public Text healthText;
    public Text currencyText;
    public Text premiumCurrencyText;
    public Text levelText;
    public Slider healthSlider;

    [Header("Combat UI")]
    public GameObject combatPanel;
    public Text enemyNameText;
    public Text enemyHealthText;
    public Slider enemyHealthSlider;
    public Text damagePopupText;

    [Header("Shop UI")]
    public GameObject shopPanel;
    public Transform shopItemContainer;
    public GameObject shopItemPrefab;

    private void Start()
    {
        PlayerStats stats = PlayerStats.Instance;
        if (stats != null)
        {
            stats.OnHealthChanged += UpdateHealthUI;
            stats.OnCurrencyChanged += UpdateCurrencyUI;
            stats.OnPremiumCurrencyChanged += UpdatePremiumCurrencyUI;
            stats.OnPlayerDied += OnPlayerDied;

            UpdateAllUI();
        }

        if (ShopManager.Instance != null)
        {
            ShopManager.Instance.OnItemPurchased += OnItemPurchased;
            ShopManager.Instance.OnPurchaseFailed += OnPurchaseFailed;
        }

        if (CombatManager.Instance != null)
        {
            CombatManager.Instance.OnPlayerAttacked += ShowPlayerDamage;
            CombatManager.Instance.OnEnemyAttacked += ShowEnemyDamage;
            CombatManager.Instance.OnEnemyDefeated += OnEnemyDefeated;
            CombatManager.Instance.OnPlayerDefeated += OnPlayerDefeated;
        }
    }

    private void UpdateAllUI()
    {
        PlayerStats stats = PlayerStats.Instance;
        UpdateHealthUI(stats.currentHealth, stats.maxHealth);
        UpdateCurrencyUI(stats.currency);
        UpdatePremiumCurrencyUI(stats.premiumCurrency);
        UpdateLevelUI();
    }

    private void UpdateHealthUI(float current, float max)
    {
        if (healthText != null)
            healthText.text = $"HP: {Mathf.RoundToInt(current)}/{Mathf.RoundToInt(max)}";
        if (healthSlider != null)
        {
            healthSlider.maxValue = max;
            healthSlider.value = current;
        }
    }

    private void UpdateCurrencyUI(int amount)
    {
        if (currencyText != null)
            currencyText.text = $"Gold: {amount}";
    }

    private void UpdatePremiumCurrencyUI(int amount)
    {
        if (premiumCurrencyText != null)
            premiumCurrencyText.text = $"Gems: {amount}";
    }

    private void UpdateLevelUI()
    {
        if (levelText != null)
            levelText.text = $"Lv. {PlayerStats.Instance.playerLevel}";
    }

    private void ShowPlayerDamage(DamageResult result)
    {
        string critText = result.isCritical ? " CRIT!" : "";
        Debug.Log($"Player dealt {result.damage} damage!{critText}");

        if (damagePopupText != null)
        {
            damagePopupText.text = $"-{result.damage}{critText}";
        }

        UpdateEnemyCombatUI();
    }

    private void ShowEnemyDamage(DamageResult result)
    {
        Debug.Log($"Enemy dealt {result.damage} damage to player!");
        UpdateAllUI();
    }

    private void UpdateEnemyCombatUI()
    {
        EnemyData enemy = CombatManager.Instance?.currentEnemy;
        if (enemy == null) return;

        if (enemyNameText != null)
            enemyNameText.text = enemy.enemyName;
        if (enemyHealthText != null)
            enemyHealthText.text = $"HP: {Mathf.RoundToInt(enemy.currentHealth)}/{Mathf.RoundToInt(enemy.maxHealth)}";
        if (enemyHealthSlider != null)
        {
            enemyHealthSlider.maxValue = enemy.maxHealth;
            enemyHealthSlider.value = enemy.currentHealth;
        }
    }

    public void OpenShop()
    {
        if (shopPanel != null)
            shopPanel.SetActive(true);
        PopulateShop();
    }

    public void CloseShop()
    {
        if (shopPanel != null)
            shopPanel.SetActive(false);
    }

    private void PopulateShop()
    {
        if (shopItemContainer == null || shopItemPrefab == null) return;

        // Clear existing items
        foreach (Transform child in shopItemContainer)
        {
            Destroy(child.gameObject);
        }

        List<ShopItem> availableItems = ShopDatabase.Instance.GetAvailableItems();
        foreach (ShopItem item in availableItems)
        {
            GameObject itemObj = Instantiate(shopItemPrefab, shopItemContainer);
            ShopItemUI itemUI = itemObj.GetComponent<ShopItemUI>();
            if (itemUI != null)
            {
                itemUI.Setup(item);
            }
        }
    }

    private void OnItemPurchased(ShopItem item)
    {
        Debug.Log($"Purchased: {item.itemName}");
        UpdateAllUI();
        PopulateShop();
    }

    private void OnPurchaseFailed(string reason)
    {
        Debug.Log($"Purchase failed: {reason}");
    }

    private void OnEnemyDefeated(EnemyData enemy)
    {
        Debug.Log($"Defeated {enemy.enemyName}! Earned {enemy.currencyReward} gold.");
        if (combatPanel != null)
            combatPanel.SetActive(false);
        UpdateAllUI();
    }

    private void OnPlayerDefeated()
    {
        Debug.Log("Player defeated!");
        if (combatPanel != null)
            combatPanel.SetActive(false);
    }

    private void OnPlayerDied()
    {
        Debug.Log("Game Over!");
    }

    private void OnDestroy()
    {
        PlayerStats stats = PlayerStats.Instance;
        if (stats != null)
        {
            stats.OnHealthChanged -= UpdateHealthUI;
            stats.OnCurrencyChanged -= UpdateCurrencyUI;
            stats.OnPremiumCurrencyChanged -= UpdatePremiumCurrencyUI;
            stats.OnPlayerDied -= OnPlayerDied;
        }
    }
}

// ShopItemUI.cs - Individual shop item UI element
public class ShopItemUI : MonoBehaviour
{
    public Text itemNameText;
    public Text descriptionText;
    public Text priceText;
    public Image iconImage;
    public Button buyButton;
    public Text buyButtonText;

    private ShopItem shopItem;

    public void Setup(ShopItem item)
    {
        shopItem = item;

        if (itemNameText != null)
            itemNameText.text = item.itemName;
        if (descriptionText != null)
            descriptionText.text = item.description;
        if (iconImage != null && item.icon != null)
            iconImage.sprite = item.icon;

        UpdatePriceDisplay();

        if (buyButton != null)
        {
            buyButton.onClick.RemoveAllListeners();
            buyButton.onClick.AddListener(OnBuyClicked);
        }

        UpdateButtonState();
    }

    private void UpdatePriceDisplay()
    {
        if (priceText == null) return;

        if (shopItem.isPremiumOnly)
        {
            int price = PriceCalculator.Instance.CalculatePremiumPrice(shopItem);
            priceText.text = $"{price} Gems";
        }
        else
        {
            int price = PriceCalculator.Instance.CalculatePrice(shopItem);
            priceText.text = $"{price} Gold";
        }

        if (PriceCalculator.Instance.isSaleActive)
        {
            priceText.text += " (SALE!)";
        }
    }

    private void UpdateButtonState()
    {
        if (buyButton == null) return;

        bool canAfford = ShopManager.Instance.CanAfford(shopItem);
        bool meetsReqs = ShopManager.Instance.MeetsRequirements(shopItem);
        bool alreadyOwned = IsEquipment() && PlayerStats.Instance.HasItem(shopItem.itemId);

        buyButton.interactable = canAfford && meetsReqs && !alreadyOwned;

        if (buyButtonText != null)
        {
            if (alreadyOwned)
                buyButtonText.text = "Owned";
            else if (!meetsReqs)
                buyButtonText.text = $"Lv.{shopItem.requiredLevel}";
            else if (!canAfford)
                buyButtonText.text = "Can't Afford";
            else
                buyButtonText.text = "Buy";
        }
    }

    private bool IsEquipment()
    {
        return shopItem.itemType == ItemType.Weapon ||
               shopItem.itemType == ItemType.Armor ||
               shopItem.itemType == ItemType.Cosmetic;
    }

    private void OnBuyClicked()
    {
        PurchaseResult result = ShopManager.Instance.TryPurchaseItem(shopItem.itemId);
        if (result == PurchaseResult.Success)
        {
            UpdateButtonState();
            UpdatePriceDisplay();
        }
    }
}

// GameInitializer.cs - Sets up all game systems
public class GameInitializer : MonoBehaviour
{
    private void Awake()
    {
        // Ensure all singleton managers exist
        EnsureManager<PlayerStats>("PlayerStats");
        EnsureManager<DamageCalculator>("DamageCalculator");
        EnsureManager<ShopDatabase>("ShopDatabase");
        EnsureManager<PriceCalculator>("PriceCalculator");
        EnsureManager<ShopManager>("ShopManager");
        EnsureManager<IAPManager>("IAPManager");
        EnsureManager<CombatManager>("CombatManager");
    }

    private void EnsureManager<T>(string name) where T : MonoBehaviour
    {
        if (FindObjectOfType<T>() == null)
        {
            GameObject obj = new GameObject(name);
            obj.AddComponent<T>();
        }
    }

